package service;
import model.Course;
import repository.FileManager;
import java.util.ArrayList;

public class CourseService {
    public ArrayList<Course> courses;
    private FileManager fileManager;
    private int courseCounter = 1;
    public CourseService(){
        this.courses = new ArrayList<>();
        this.fileManager = new FileManager();
        loadFromFile();
    }
    public void loadFromFile(){
        ArrayList<String[]> data = fileManager.loadCourses();
        for (String[] parts : data){
            if (parts.length == 3){
                courses.add(new Course(Integer.parseInt(parts[0]),parts[1],Integer.parseInt(parts[2])));
                courseCounter = Integer.parseInt(parts[0]) + 1;


            }
        }
    }
    public boolean addCourse(String courseName, int credits){
        Course course = new Course (courseCounter++, courseName , credits);
        courses.add(course);
        fileManager.saveCourse(course);
        System.out.println("THe course has been added " + courseName);
        return true ;
    }
    public boolean checkAvailability(int courseId){
        for (Course c : courses){
            if (c.getCourseId() == courseId)
                return true;
        }
        return false;
    }
    public Course getCourseById(int courseId){
        for (Course c : courses){
            if (c.getCourseId() == courseId)
                return c;
        }
        return null;
    }
    public void viewCourses(){
        if (courses.isEmpty()){
            System.out.println("No course Available");
            return;
        }
        for (Course c : courses){
            System.out.println(c.displayCourse());
        }
    }
    public ArrayList<Course>getCourses(){
        return courses;
    }
}

package service;
import model.Course;
import repository.FileManager;
import java.util.ArrayList;

public class CourseService {
    public ArrayList<Course> courses;
    private FileManager fileManager;
    private int courseCounter = 1;
    public CourseService(){
        this.courses = new ArrayList<>();
        this.fileManager = new FileManager();
        loadFromFile();
    }
    public void loadFromFile(){
        ArrayList<String[]> data = fileManager.loadCourses();
        for (String[] parts : data){
            if (parts.length != 3){
                continue;
            }
            try {
                int id = Integer.parseInt(parts[0].trim());
                int credits = Integer.parseInt(parts[2].trim());
                courses.add(new Course(id, parts[1], credits));
                courseCounter = Math.max(courseCounter, id + 1);
            } catch (NumberFormatException ex) {
                System.out.println("Skipping malformed course row: " + String.join(",", parts));
            }
        }
    }
    public boolean addCourse(String courseName, int credits){
        Course course = new Course (courseCounter++, courseName , credits);
        courses.add(course);
        fileManager.saveCourse(course);
        System.out.println("THe course has been added " + courseName);
        return true ;
    }
    public boolean checkAvailability(int courseId){
        for (Course c : courses){
            if (c.getCourseId() == courseId)
                return true;
        }
        return false;
    }
    public Course getCourseById(int courseId){
        for (Course c : courses){
            if (c.getCourseId() == courseId)
                return c;
        }
        return null;
    }
    public void viewCourses(){
        if (courses.isEmpty()){
            System.out.println("No course Available");
            return;
        }
        for (Course c : courses){
            System.out.println(c.displayCourse());
        }
    }
    public ArrayList<Course>getCourses(){
        return courses;
    }
}

package service;
import model.Course;
import model.Enrollment;
import repository.FileManager;
import java.util.ArrayList;
import java.time.LocalDate;

public class EnrollmentService {
    private ArrayList<Enrollment> enrollments;
    private FileManager fileManager;
    private CourseService courseService;
    private int enrollmentCounter = 1;

    public EnrollmentService(CourseService courseService){
        this.enrollments = new ArrayList<>();
        this.fileManager = new FileManager();
        this.courseService = courseService;
        loadFromFile();
    }
    private void loadFromFile(){
        ArrayList<String[]>data = fileManager.loadEnrollments();
        for (String[]parts : data){
            if (parts.length == 4){
                enrollments.add(new Enrollment(Integer.parseInt(parts[0]), parts[3] ,Integer.parseInt(parts[1]), Integer.parseInt(parts[2])));
                enrollmentCounter = Integer.parseInt(parts[0] + 1);
            }
        }

    }
    public void selectCourse(int studentId,int courseId){
        boolean available = courseService.checkAvailability(courseId);
        if (available){
            Enrollment enrollment = new Enrollment(enrollmentCounter++,LocalDate.now().toString(),studentId,courseId);
            enrollments.add(enrollment);
            fileManager.saveEnrollment(enrollment);
            System.out.println("Enrollment confirmed ID : " + enrollment.getEnrollmentId());
        }else{
            System.out.println("Error : course not available");
        }


    }
    public boolean dropCourse(int enrollmentId){
        for (Enrollment e : enrollments){
            if (e.getEnrollmentId() == enrollmentId){
                enrollments.remove(e);
                fileManager.deleteEnrollment(enrollmentId);
                System.out.println("Course dropped ");
                return true;
            }
        }
        System.out.println("Enrollment not found");
        return false;
    }
    public void viewEnrollments(int studentId){
        boolean found = false;
        for (Enrollment e : enrollments ){
            if (e.getStudentId() == studentId){
                Course course = courseService.getCourseById(e.getCourseId());
                System.out.println("Enrollment ID : " + e.getEnrollmentId() + " Course : " + (course != null ? course.getCourseName() : e.getCourseId()) + "Date : " + e.getEnrollmentDate());
                found = true;
            }
        }
        if (!found){
            System.out.println("Enrollment not found ");

        }
        }
        public ArrayList<Enrollment>getEnrollments(){
            return enrollments;

        }

}

