package ui;

import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Scene;
import javafx.stage.Stage;

public class MainApp extends Application {

    @Override
    public void start(Stage stage) throws Exception {
        FXMLLoader loader = new FXMLLoader(getClass().getResource("/ui/view/dashboard.fxml"));
        Scene scene = new Scene(loader.load(), 1100, 700);
        stage.setTitle("Online Course Enrollment");
        stage.setScene(scene);
        stage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

package ui;

import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Scene;
import javafx.stage.Stage;

public class MainApp extends Application {

    @Override
    public void start(Stage stage) throws Exception {
        FXMLLoader loader = new FXMLLoader(getClass().getResource("/ui/view/dashboard.fxml"));
        Scene scene = new Scene(loader.load(), 1100, 700);
        String stylesheet = getClass().getResource("/ui/view/style.css").toExternalForm();
        scene.getStylesheets().add(stylesheet);
        stage.setTitle("Online Course Enrollment");
        stage.setScene(scene);
        stage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

/* ============================================
   Online Course Enrollment System - Stylesheet
   ============================================ */

/* Root styling */
.root {
    -fx-font-family: 'Segoe UI', 'Arial', sans-serif;
    -fx-font-size: 11px;
    -fx-background-color: #f5f5f5;
}

/* ============================================
   Labels & Text
   ============================================ */
Label {
    -fx-text-fill: #333333;
}

Label:header {
    -fx-font-size: 22px;
    -fx-font-weight: bold;
    -fx-text-fill: #1e3a8a;
}

/* ============================================
   Text Fields & Input
   ============================================ */
TextField {
    -fx-padding: 8px;
    -fx-border-color: #d1d5db;
    -fx-border-width: 1px;
    -fx-border-radius: 4px;
    -fx-background-color: #ffffff;
    -fx-text-fill: #333333;
    -fx-font-size: 11px;
}

TextField:focused {
    -fx-border-color: #3b82f6;
    -fx-border-width: 2px;
    -fx-background-color: #ffffff;
}

TextField:disabled {
    -fx-background-color: #e5e7eb;
    -fx-text-fill: #9ca3af;
}

/* ============================================
   Buttons
   ============================================ */
Button {
    -fx-padding: 8px 16px;
    -fx-background-color: #3b82f6;
    -fx-text-fill: #ffffff;
    -fx-font-size: 11px;
    -fx-font-weight: bold;
    -fx-border-radius: 4px;
    -fx-cursor: hand;
}

Button:hover {
    -fx-background-color: #2563eb;
}

Button:pressed {
    -fx-background-color: #1d4ed8;
}

/* Refresh button - accent color */
Button:default {
    -fx-background-color: #10b981;
}

Button:default:hover {
    -fx-background-color: #059669;
}

Button:default:pressed {
    -fx-background-color: #047857;
}

/* Drop button - danger color */
.button-danger {
    -fx-background-color: #ef4444;
}

.button-danger:hover {
    -fx-background-color: #dc2626;
}

.button-danger:pressed {
    -fx-background-color: #b91c1c;
}

/* ============================================
   ComboBox
   ============================================ */
ComboBox {
    -fx-padding: 8px;
    -fx-border-color: #d1d5db;
    -fx-border-width: 1px;
    -fx-border-radius: 4px;
    -fx-background-color: #ffffff;
    -fx-text-fill: #333333;
}

ComboBox:focused {
    -fx-border-color: #3b82f6;
    -fx-border-width: 2px;
}

.combo-box-popup .list-view {
    -fx-background-color: #ffffff;
}

.combo-box-popup .list-view .list-cell {
    -fx-padding: 8px;
    -fx-text-fill: #333333;
}

.combo-box-popup .list-view .list-cell:filled:selected {
    -fx-background-color: #dbeafe;
    -fx-text-fill: #1e3a8a;
}

/* ============================================
   Tables
   ============================================ */
TableView {
    -fx-background-color: #ffffff;
    -fx-border-color: #e5e7eb;
    -fx-border-width: 1px;
    -fx-border-radius: 4px;
}

TableView:focused {
    -fx-border-color: #3b82f6;
    -fx-border-width: 2px;
}

TableColumn {
    -fx-text-alignment: CENTER;
}

.table-view .column-header,
.table-view .column-header-background,
.table-view .column-header-background .filler {
    -fx-background-color: #f3f4f6;
    -fx-border-color: #e5e7eb;
}

.table-view .column-header .label {
    -fx-text-fill: #1f2937;
    -fx-font-weight: bold;
}

.table-view .table-row-cell {
    -fx-padding: 8px;
    -fx-border-color: #e5e7eb;
}

.table-view .table-row-cell:filled {
    -fx-background-color: #ffffff;
    -fx-text-fill: #333333;
}

.table-view .table-row-cell:filled:selected {
    -fx-background-color: #dbeafe;
    -fx-text-fill: #1e3a8a;
}

.table-view .table-row-cell:filled:selected:focused {
    -fx-background-color: #bfdbfe;
}

.table-view .table-row-cell:odd {
    -fx-background-color: #f9fafb;
}

.table-view .table-row-cell:odd:selected {
    -fx-background-color: #dbeafe;
    -fx-text-fill: #1e3a8a;
}

/* ============================================
   TabPane & Tabs
   ============================================ */
TabPane {
    -fx-background-color: #ffffff;
}

.tab {
    -fx-padding: 12px 20px;
    -fx-background-color: #f3f4f6;
    -fx-text-fill: #6b7280;
    -fx-font-size: 12px;
    -fx-font-weight: bold;
    -fx-border-color: #e5e7eb;
}

.tab:selected {
    -fx-background-color: #ffffff;
    -fx-text-fill: #3b82f6;
    -fx-border-color: #3b82f6;
    -fx-border-width: 0px 0px 3px 0px;
}

.tab:hover {
    -fx-background-color: #eff6ff;
}

.tab-pane .tab-header-background {
    -fx-background-color: #f3f4f6;
    -fx-border-color: #e5e7eb;
    -fx-border-width: 0px 0px 1px 0px;
}

/* ============================================
   VBox & HBox Layout
   ============================================ */
VBox {
    -fx-spacing: 10px;
}

HBox {
    -fx-spacing: 8px;
}

/* ============================================
   BorderPane
   ============================================ */
BorderPane {
    -fx-background-color: #f5f5f5;
}

/* ============================================
   Scrollbar
   ============================================ */
.scroll-bar {
    -fx-font-size: 10px;
}

.scroll-bar:vertical .increment-button,
.scroll-bar:vertical .decrement-button,
.scroll-bar:horizontal .increment-button,
.scroll-bar:horizontal .decrement-button {
    -fx-padding: 0px;
}

.scroll-bar .thumb {
    -fx-background-color: #cbd5e1;
    -fx-background-radius: 4px;
}

.scroll-bar .thumb:hover {
    -fx-background-color: #94a3b8;
}

/* ============================================
   Alert Dialogs
   ============================================ */
.alert {
    -fx-background-color: #ffffff;
}

.alert .header-panel {
    -fx-background-color: #fee2e2;
}

.alert .header-panel .text {
    -fx-text-fill: #991b1b;
    -fx-font-weight: bold;
}

.alert .content-panel {
    -fx-background-color: #ffffff;
    -fx-padding: 12px;
}

.alert .label {
    -fx-text-fill: #333333;
}

/* ============================================
   Focus / Disabled States
   ============================================ */
:disabled {
    -fx-opacity: 0.6;
}

:focused {
    -fx-focus-color: #bfdbfe;
    -fx-faint-focus-color: #dbeafe;
}
